/**
 * 로그인 매칭. doctorId + password 검증 후 의사 객체 반환.
 * 비밀번호 필드는 반환 객체에서 제거 — sessionStorage 진입 금지.
 *
 * @param {string} doctorId
 * @param {string} password
 * @returns {object|null}  매칭 실패 시 null
 */
export function findDoctor(doctorId, password) {
  const trimmedId = (doctorId || '').trim().toLowerCase();
  const d = SEED_DOCTORS.find(x => x.doctorId.toLowerCase() === trimmedId);
  if (!d) return null;
  if (d.password !== password) return null;
  const { password: _omit, ...safe } = d;
  return safe;
}

/** UI 힌트(자동완성·드롭다운) 용 — 비번 제외 메타만 노출. */
export function listDoctorHints() {
  return SEED_DOCTORS.map(d => ({
    doctorId:    d.doctorId,
    name:        d.name,
    institution: d.institution,
    emrVendor:   d.emrVendor,
  }));
}
