/* ----- LR 막대 (Robinson 2020 Fig.2 양식) — 좌 반박(빨강) · 우 지지(녹색) ----- */
function LRBar({ rank, name, prob, rare, dontMiss, orpha }) {
  // prob을 LR 양수/음수로 변환 (시뮬레이션)
  const lrSupport = prob; // 0~1
  const supportPct = Math.round(lrSupport * 100);

  const borderColor = dontMiss ? 'var(--rl-amber)' : rare ? 'var(--rl-rare)' : 'transparent';

  return (
    <div
      className="px-2 py-1.5 rounded"
      style={{
        border: `1px solid ${dontMiss || rare ? borderColor : 'var(--rl-border-soft)'}`,
        background: 'white',
      }}
    >
      <div className="flex items-baseline gap-2 mb-1">
        <span className="font-mono text-[10px] w-4" style={{ color: 'var(--rl-ink-3)' }}>#{rank}</span>
        <span className="text-[12px] font-medium truncate flex-1" style={{ color: 'var(--rl-ink)' }}>
          <BiText>{name}</BiText>
        </span>
        {rare && <Flame size={10} style={{ color: 'var(--rl-rare)' }} />}
        {dontMiss && <AlertTriangle size={10} style={{ color: 'var(--rl-amber)' }} />}
        <span className="font-mono text-[10px]" style={{ color: 'var(--rl-ink-2)' }}>
          {(prob * 100).toFixed(0)}%
        </span>
      </div>
      {/* LR 막대 */}
      <div className="relative h-2 rounded" style={{ background: 'var(--rl-bg-3)' }}>
        <div
          className="absolute h-full rounded"
          style={{
            left: '50%',
            width: `${supportPct / 2}%`,
            background: 'var(--rl-teal)',
          }}
        />
        {/* 중앙선 */}
        <div className="absolute top-0 bottom-0" style={{ left: '50%', width: 1, background: 'var(--rl-ink-3)' }} />
      </div>
      {orpha && (
        <div className="font-mono text-[9px] mt-1" style={{ color: 'var(--rl-rare)' }}>{orpha}</div>
      )}
    </div>
  );
}

